네, React에서 다크 모드 토글 컴포넌트 예시 코드를 보여드릴게요. `useState`와 `useEffect`를 사용하여 간단하게 구현할 수 있습니다.

```jsx
import React, { useState, useEffect } from 'react';

function DarkModeToggle() {
  // 테마 상태를 관리합니다. 초기값은 로컬 스토리지에서 가져오거나 기본값(light)으로 설정합니다.
  const [theme, setTheme] = useState(() => {
    const savedTheme = localStorage.getItem('theme');
    return savedTheme ? savedTheme : 'light';
  });

  // theme 상태가 변경될 때마다 body의 class를 업데이트하고 로컬 스토리지에 저장합니다.
  useEffect(() => {
    document.body.className = theme; // body에 'light' 또는 'dark' 클래스를 추가
    localStorage.setItem('theme', theme); // 로컬 스토리지에 현재 테마 저장
  }, [theme]); // theme 상태가 변경될 때만 이 효과를 다시 실행

  // 테마를 토글하는 함수
  const toggleTheme = () => {
    setTheme((prevTheme) => (prevTheme === 'light' ? 'dark' : 'light'));
  };

  return (
    <button
      onClick={toggleTheme}
      style={{
        padding: '10px 20px',
        fontSize: '16px',
        cursor: 'pointer',
        borderRadius: '5px',
        border: '1px solid #ccc',
        backgroundColor: theme === 'light' ? '#f0f0f0' : '#333',
        color: theme === 'light' ? '#333' : '#f0f0f0',
      }}
    >
      {theme === 'light' ? '다크 모드로 전환' : '라이트 모드로 전환'}
    </button>
  );
}

export default DarkModeToggle;
```

**설명:**

1.  **`useState`**: `theme` 상태를 관리합니다. 초기값은 `localStorage`에 저장된 값이 있으면 그 값을 사용하고, 없으면 `'light'`를 기본값으로 설정합니다.
2.  **`useEffect`**: `theme` 상태가 변경될 때마다 실행됩니다.
    *   `document.body.className = theme;`를 통해 `<body>` 태그에 현재 테마(예: `'light'` 또는 `'dark'`)에 해당하는 클래스를 추가합니다. 이 클래스를 기반으로 CSS에서 스타일을 적용할 수 있습니다.
    *   `localStorage.setItem('theme', theme);`를 통해 사용자가 선택한 테마를 브라우저의 로컬 스토리지에 저장하여 페이지를 새로고침해도 테마가 유지되도록 합니다.
3.  **`toggleTheme` 함수**: 버튼 클릭 시 현재 `theme` 상태를 반대(light ↔ dark)로 변경합니다.
4.  **CSS 적용 (예시)**: 이 컴포넌트와 함께 사용하려면 CSS 파일에 다음과 같이 `body` 클래스에 대한 스타일을 정의해야 합니다.

    ```css
    /* App.css 또는 전역 CSS 파일 */
    body.light {
      background-color: #ffffff;
      color: #333333;
    }

    body.dark {
      background-color: #333333;
      color: #ffffff;
    }
    ```

이 코드를 사용하면 간단하게 다크 모드 토글 기능을 구현할 수 있습니다. 필요에 따라 `Context API`나 `Redux` 같은 상태 관리 라이브러리를 사용하여 테마 상태를 전역적으로 관리할 수도 있습니다.

네, React에서 다크 모드 토글 컴포넌트를 구현하는 간단한 예시 코드를 보여드릴게요. `useState`와 `useEffect` 훅을 사용하여 다크 모드 상태를 관리하고, 이 상태에 따라 `body` 태그에 클래스를 추가하여 스타일을 변경하는 방식입니다.

**1. `DarkModeToggle.js` 파일 (컴포넌트)**

```jsx
import React, { useState, useEffect } from 'react';
import './DarkModeToggle.css'; // CSS 파일을 임포트합니다.

function DarkModeToggle() {
  // 다크 모드 상태를 관리합니다. 초기값은 로컬 스토리지에서 가져오거나 기본값(false)으로 설정합니다.
  const [isDarkMode, setIsDarkMode] = useState(
    () => localStorage.getItem('theme') === 'dark'
  );

  // isDarkMode 상태가 변경될 때마다 실행됩니다.
  useEffect(() => {
    const body = document.body;
    if (isDarkMode) {
      body.classList.add('dark-mode');
      localStorage.setItem('theme', 'dark'); // 로컬 스토리지에 다크 모드 상태 저장
    } else {
      body.classList.remove('dark-mode');
      localStorage.setItem('theme', 'light'); // 로컬 스토리지에 라이트 모드 상태 저장
    }
  }, [isDarkMode]); // isDarkMode가 변경될 때만 이 효과를 다시 실행합니다.

  const toggleDarkMode = () => {
    setIsDarkMode(prevMode => !prevMode); // 현재 상태를 반전시킵니다.
  };

  return (
    <div className="dark-mode-toggle-container">
      <button onClick={toggleDarkMode} className="dark-mode-button">
        {isDarkMode ? '라이트 모드로 전환' : '다크 모드로 전환'}
      </button>
      <p>현재 모드: {isDarkMode ? '다크 모드' : '라이트 모드'}</p>
    </div>
  );
}

export default DarkModeToggle;
```

**2. `DarkModeToggle.css` 파일 (스타일)**

```css
/* 기본 (라이트) 모드 스타일 */
body {
  background-color: #ffffff;
  color: #333333;
  transition: background-color 0.3s ease, color 0.3s ease; /* 부드러운 전환 효과 */
}

/* 다크 모드 스타일 */
body.dark-mode {
  background-color: #333333;
  color: #ffffff;
}

.dark-mode-toggle-container {
  margin: 20px;
  padding: 15px;
  border: 1px solid #ccc;
  border-radius: 8px;
  background-color: #f9f9f9;
  text-align: center;
}

body.dark-mode .dark-mode-toggle-container {
  background-color: #444444;
  border-color: #555;
}

.dark-mode-button {
  padding: 10px 15px;
  font-size: 16px;
  cursor: pointer;
  border: none;
  border-radius: 5px;
  background-color: #007bff;
  color: white;
  margin-bottom: 10px;
  transition: background-color 0.3s ease;
}

.dark-mode-button:hover {
  background-color: #0056b3;
}

body.dark-mode .dark-mode-button {
  background-color: #6c757d;
}

body.dark-mode .dark-mode-button:hover {
  background-color: #5a6268;
}
```

**3. `App.js` 파일 (사용 예시)**

```jsx
import React from 'react';
import DarkModeToggle from './DarkModeToggle'; // 컴포넌트를 임포트합니다.
import './App.css'; // 필요하다면 App 전역 CSS

function App() {
  return (
    <div className="App">
      <header className="App-header">
        <h1>나의 멋진 React 앱</h1>
        <DarkModeToggle /> {/* 다크 모드 토글 컴포넌트를 렌더링합니다. */}
        <p>이것은 앱의 콘텐츠입니다. 다크 모드 토글 버튼을 눌러보세요!</p>
      </header>
    </div>
  );
}

export default App;
```

**설명:**

1.  **`useState`**: `isDarkMode`라는 상태 변수를 만들고, 초기값은 사용자의 로컬 스토리지에 저장된 테마 설정(`'dark'`인지 `'light'`인지)을 확인하여 설정합니다.
2.  **`useEffect`**: `isDarkMode` 상태가 변경될 때마다 `document.body`에 `dark-mode` 클래스를 추가하거나 제거합니다. 또한, 사용자가 페이지를 새로고침해도 테마 설정이 유지되도록 로컬 스토리지에 현재 테마 상태를 저장합니다.
3.  **`toggleDarkMode` 함수**: 버튼 클릭 시 `isDarkMode` 상태를 반전시키는 함수입니다.
4.  **CSS**: `body` 태그에 `dark-mode` 클래스가 있을 때와 없을 때의 스타일을 정의하여 배경색, 글자색 등을 변경합니다. `transition` 속성을 사용하여 모드 전환이 부드럽게 보이도록 했습니다.

이 코드를 사용하면 React 앱에서 간단하게 다크 모드 기능을 구현할 수 있습니다.
